import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"董事会治理","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/董事会治理.md","filePath":"05_quotes/by-theme/董事会治理.md"}'),r={name:"05_quotes/by-theme/董事会治理.md"};function l(q,t,c,_,p,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="董事会治理" tabindex="-1">董事会治理 <a class="header-anchor" href="#董事会治理" aria-label="Permalink to &quot;董事会治理&quot;">​</a></h1><blockquote><p>&quot;不要让糟糕的董事会控制你的公司。董事会应该代表股东利益，而不是管理层的利益。&quot;——巴菲特</p></blockquote><p>公司治理是巴菲特晚年最关注的议题之一。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;糟糕的董事会会毁掉优秀的企业。好的董事会应该在问题出现之前就发现它。&quot;</p></blockquote><blockquote><p>&quot;我见过的最糟糕的公司治理，是那些CEO薪酬由CEO自己决定的公司董事会。利益冲突是治理失败的根本原因。&quot;</p></blockquote><blockquote><p>&quot;我们的董事会成员大多和我们有长期关系，他们理解伯克希尔的文化。我们不需要太多独立董事，但我们需要真正独立思考的人。&quot;</p></blockquote><blockquote><p>&quot;CEO连任的投票结果不应该由CEO来决定。让CEO来设计投票规则，就像让狐狸来决定鸡舍的管理方案。&quot;</p></blockquote><blockquote><p>&quot;公司治理的核心问题是：谁在监督监督者？董事会是答案，但谁来监督董事会？答案是股东本身。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1992年 · 1998年 · 2006年 · 2010年 · 2015年 · 2020年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
